import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../../services/api';
import { Edit, Trash2, Plus } from 'lucide-react';

const BASE_URL = 'http://localhost:5000';

const ProductsList = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchProducts = async () => {
    try {
      const { data } = await api.get('/products');
      setProducts(data);
    } catch (error) {
      console.error('Error fetching products:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchProducts(); }, []);

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this product?')) {
      try {
        await api.delete(`/products/${id}`);
        setProducts(products.filter(p => p._id !== id));
      } catch (error) {
        console.error('Error deleting product:', error);
      }
    }
  };

  if (loading) return <div>Loading products...</div>;

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-3xl font-serif font-bold">Products</h1>
        <Link to="/admin/products/new" className="bg-black text-white px-4 py-2 rounded flex items-center gap-2 hover:bg-gray-dark transition-colors">
          <Plus size={18} /><span>New Product</span>
        </Link>
      </div>
      <div className="bg-white border border-border rounded-lg overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-gray-light text-gray-dark text-sm uppercase tracking-wider">
              <th className="p-4 font-medium border-b border-border w-16">Image</th>
              <th className="p-4 font-medium border-b border-border">Name</th>
              <th className="p-4 font-medium border-b border-border">Category</th>
              <th className="p-4 font-medium border-b border-border">Price</th>
              <th className="p-4 font-medium border-b border-border">Stock</th>
              <th className="p-4 font-medium border-b border-border text-right">Actions</th>
            </tr>
          </thead>
          <tbody>
            {products.length === 0 ? (
              <tr><td colSpan="6" className="p-8 text-center text-gray-dark">No products found. Create one!</td></tr>
            ) : products.map((product) => (
              <tr key={product._id} className="hover:bg-gray-50 transition-colors">
                <td className="p-4 border-b border-border">
                  <div className="w-12 h-12 bg-gray-light rounded overflow-hidden">
                    {product.imageUrl && <img src={`${BASE_URL}${product.imageUrl}`} alt={product.name} className="w-full h-full object-cover" />}
                  </div>
                </td>
                <td className="p-4 border-b border-border font-medium">
                  {product.name}
                  {product.featured && <span className="ml-2 text-xs bg-black text-white px-2 py-0.5 rounded">Featured</span>}
                </td>
                <td className="p-4 border-b border-border text-gray-dark">{product.category}</td>
                <td className="p-4 border-b border-border">${product.price}{product.oldPrice && <span className="ml-2 text-sm text-gray-dark line-through">${product.oldPrice}</span>}</td>
                <td className="p-4 border-b border-border"><span className={product.stock > 0 ? 'text-green-600' : 'text-red-600'}>{product.stock > 0 ? product.stock : 'Out of stock'}</span></td>
                <td className="p-4 border-b border-border text-right space-x-3">
                  <Link to={`/admin/products/${product._id}`} className="inline-block text-blue-600 hover:text-blue-800"><Edit size={18} /></Link>
                  <button onClick={() => handleDelete(product._id)} className="text-red-600 hover:text-red-800"><Trash2 size={18} /></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default ProductsList;
